#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long K, d0, d1;
        scanf("%lld %lld %lld", &K, &d0, &d1);
        long long sum = d0 + d1;
        for (int i = 2; i < K; i++) {
            long long di = (sum % 10);
            sum += di;
        }
        if (sum % 3 == 0) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

