        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long K = sc.nextLong();
            long d0 = sc.nextLong();
            long d1 = sc.nextLong();
            long sum = d0 + d1;
            for (int i = 2; i < K; i++) {
                long di = (sum % 10);
                sum += di;
            }
            if (sum % 3 == 0) System.out.println("YES");
            else System.out.println("NO");
        }
    }
